from lxml import etree

def process_soap_xml(xml_request):
    # Parse the SOAP XML request
    root = etree.fromstring(xml_request.encode('utf-8'), parser=etree.XMLParser(DTD_validation=True))

    # Extract the SOAP envelope
    envelope = root.find('soapenv:Envelope')

    # Extract the SOAP message body
    body = envelope.find('soapenv:Body')

    # Return the SOAP message body
    return etree.tostring(body, encoding='utf-8')